+function drawBanner(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  const banner = [
+    "  PPP  ",
+    " PPPPP ",
+    "PPPPPPP",
+    " PPPPP ",
+    "  PPP  ",
+  ];
+  const palette = { P: "#800000" };
+  drawSpriteDef(ctx, banner, palette, x, y, s, false);
+}
+
+function drawTorch(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  const torch = [
+    "  Y  ",
+    " YRY ",
+    "YRRRY",
+    "  B  ",
+    "  B  ",
+  ];
+  const palette = { Y: "#ffcc33", R: "#cc3300", B: "#663300" };
+  drawSpriteDef(ctx, torch, palette, x, y, s, false);
+}
+
+function drawCandle(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  const candle = [
+    "  Y  ",
+    "  Y  ",
+    "  W  ",
+    "  W  ",
+    "  B  ",
+  ];
+  const palette = { Y: "#ffff66", W: "#eeeeee", B: "#444444" };
+  drawSpriteDef(ctx, candle, palette, x, y, s, false);
+}
+
+// New decoration helpers
+function drawTapestry(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  const tapestry = [
+    "RRRRRR",
+    "RBBBRR",
+    "RBBBRR",
+    "RRRRRR",
+  ];
+  const palette = { R: "#660000", B: "#cc3333" };
+  drawSpriteDef(ctx, tapestry, palette, x, y, s, false);
+}
+
+function drawWallShield(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  const shield = [
+    "  G  ",
+    " GGG ",
+    "GGGGG",
+    " GGG ",
+    "  G  ",
+  ];
+  const palette = { G: "#999966" };
+  drawSpriteDef(ctx, shield, palette, x, y, s, false);
+}
+
+function drawCandelabra(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  const candelabra = [
+    "  Y  ",
+    " YYY ",
+    "YBBBYY",
+    "  B  ",
+    "  B  ",
+  ];
+  const palette = { Y: "#ffff99", B: "#666633" };
+  drawSpriteDef(ctx, candelabra, palette, x, y, s, false);
+}
+
+function drawBarrel(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  const barrel = [
+    " BBB ",
+    "BWWWB",
+    "BWWWB",
+    " BBB ",
+  ];
+  const palette = { B: "#663300", W: "#cc9966" };
+  drawSpriteDef(ctx, barrel, palette, x, y, s, false);
+}
+
+function drawCrate(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  const crate = [
+    "RRRR",
+    "RWWR",
+    "RWWR",
+    "RRRR",
+  ];
+  const palette = { R: "#996633", W: "#cc9966" };
+  drawSpriteDef(ctx, crate, palette, x, y, s, false);
+}
+
+function drawRug(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  const rug = [
+    "GGGGGGGG",
+    "GYYYYYYG",
+    "GYYYYYYG",
+    "GGGGGGGG",
+  ];
+  const palette = { G: "#660000", Y: "#ffcc00" };
+  drawSpriteDef(ctx, rug, palette, x, y, s, false);
+}
+
+function drawRoomFurniture(ctx: CanvasRenderingContext2D, roomType: string, bounds: { x: number; y: number; w: number; h: number }) {
+  const s = 4; // pixel size scale
+  switch (roomType) {
+    case "Workshop":
+      drawBanner(ctx, bounds.x + 5, bounds.y + 5, s);
+      drawTorch(ctx, bounds.x + 40, bounds.y + 5, s);
+      drawBarrel(ctx, bounds.x + 10, bounds.y + bounds.h - 25, s);
+      drawCrate(ctx, bounds.x + 30, bounds.y + bounds.h - 25, s);
+      drawCandelabra(ctx, bounds.x + bounds.w - 25, bounds.y + 10, s);
+      break;
+    case "Healing Chamber":
+      drawTapestry(ctx, bounds.x + 5, bounds.y + 5, s);
+      drawCandle(ctx, bounds.x + 40, bounds.y + 5, s);
+      drawRug(ctx, bounds.x + 10, bounds.y + bounds.h - 30, s);
+      drawWallShield(ctx, bounds.x + bounds.w - 25, bounds.y + 10, s);
+      break;
+    case "Library":
+      drawBanner(ctx, bounds.x + 5, bounds.y + 5, s);
+      drawTorch(ctx, bounds.x + bounds.w - 25, bounds.y + 5, s);
+      drawRug(ctx, bounds.x + 10, bounds.y + bounds.h - 30, s);
+      drawTapestry(ctx, bounds.x + bounds.w / 2 - 15, bounds.y + 10, s);
+      break;
+    default:
+      drawBanner(ctx, bounds.x + 5, bounds.y + 5, s);
+      drawTorch(ctx, bounds.x + bounds.w - 25, bounds.y + 5, s);
+      drawRug(ctx, bounds.x + 10, bounds.y + bounds.h - 30, s);
+      drawCrate(ctx, bounds.x + bounds.w / 2 - 15, bounds.y + bounds.h - 25, s);
+      break;
+  }
+}
